import React, { useState, useEffect } from "react";
import "./About.css";

function About() {
  const images = [
    "/images/slide1.jpg",
    "/images/slide2.jpg",
    "/images/slide3.jpg",
    "/images/slide4.jpg",
    "/images/slide5.jpg"
  ];

  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((prevIndex) =>
        prevIndex === images.length - 1 ? 0 : prevIndex + 1
      );
    }, 4000); // change every 4s
    return () => clearInterval(interval);
  }, [images.length]);

  return (
    <section
      id="about-section"
      className="about"
      style={{ backgroundImage: `url(${images[currentIndex]})` }}
    >
      <div className="about-overlay">
        <h2>About Us</h2>
        <p>
          HEALink connects people to reliable healthcare services — book pathology,
          find blood banks, and access teleconsultations quickly. Our mission is
          to make healthcare accessible and simple.
        </p>
      </div>
    </section>
  );
}

export default About;
